<?php require_once '../../config/config.php'; requireAdmin(); if($_SERVER['REQUEST_METHOD']==='POST'){db()->prepare('INSERT INTO toppings(name,extra_price) VALUES(?,?)')->execute([$_POST['name'],$_POST['extra_price']]);} $rows=db()->query('SELECT * FROM toppings')->fetchAll(PDO::FETCH_ASSOC); ?><h2>Toppings</h2><form method="post"><input name="name"><input name="extra_price"><button>Add</button></form><?php foreach($rows as $r) echo '<p>'.e($r['name']).' '.money($r['extra_price']).'</p>'; ?>
